using System;
using System.Globalization;
using System.IO;
using System.Net;
using System.Net.Mail;
using System.Text.RegularExpressions;

namespace Shared.Infra.CrossCutting
{
    public class Email
    {
        private string _emailPadrao = "";
        private string _usuario = "";
        private string _emailPadraoSenha = "";
        private string _remententeNome = "";
        private string _smtp = "";
        private int _smtpPorta = 0;

        public Email(string emailPadrao, string usuario, string emailPadraoSenha, string remententeNome, string smtp, int smtpPorta)
        {
            _emailPadrao = emailPadrao;
            _usuario = usuario;
            _emailPadraoSenha = emailPadraoSenha;
            _remententeNome = remententeNome;
            _smtp = smtp;
            _smtpPorta = smtpPorta;
        }

        public Email()
        {
        }

        public (bool, string) EnviarEmail(string emailDestinatario, string htmlMsg, string assunto)
        {
            ServicePointManager.ServerCertificateValidationCallback = (obj, certificate, chain, errors) => true;

            MailMessage email = new MailMessage();

            email.From = new MailAddress(_emailPadrao, _remententeNome, System.Text.Encoding.UTF8);

            emailDestinatario = emailDestinatario.Replace(" ", ""); //para tirar espaços.

            string[] vetDestinarios = emailDestinatario.Split(',');
            if (vetDestinarios != null && vetDestinarios.Length > 1)
            {
                foreach (string item in vetDestinarios)
                {
                    try
                    {
                        email.CC.Add(item);
                    }
                    catch
                    {
                        //Para não parar o envio de múltiplos emails quando um e-mail está inválido.
                    }
                }
            }
            else email.To.Add(emailDestinatario);

            email.ReplyToList.Add(new MailAddress(_emailPadrao));

            email.IsBodyHtml = true;
            email.SubjectEncoding = System.Text.Encoding.UTF8;
            email.BodyEncoding = System.Text.Encoding.UTF8;

           string estruturaHtml = "";

            estruturaHtml = "<!DOCTYPE html>";
            estruturaHtml += "<html lang=\"pt-BR\">";
            estruturaHtml += "<head><meta charset=\"UTF-8\" /><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\" /></head>";
            estruturaHtml += "<body style=\"margin:0;padding:0;background-color:#f0f2f5;font-family:Arial,Helvetica,sans-serif;\">";

            // Wrapper
            estruturaHtml += "<table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"background-color:#f0f2f5;padding:40px 0;\">";
            estruturaHtml += "<tr><td align=\"center\">";

            // Container principal
            estruturaHtml += "<table width=\"600\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"max-width:600px;width:100%;background-color:#ffffff;border-radius:8px;overflow:hidden;\">";

            // Header com logo
            estruturaHtml += "<tr>";
            estruturaHtml += "<td align=\"center\" style=\"background-color:#0f172a;padding:28px 40px;\">";
            estruturaHtml += "<img src=\"data:image/png;base64,\" alt=\"MultiServiços\" height=\"42\" style=\"display:block;border:0;\" />";

            estruturaHtml += "</td>";
            estruturaHtml += "</tr>";

            // Barra decorativa
            estruturaHtml += "<tr><td style=\"height:3px;background-color:#4f46e5;\"></td></tr>";

            // Corpo
            estruturaHtml += "<tr>";
            estruturaHtml += "<td style=\"padding:40px 48px;color:#374151;font-size:15px;line-height:1.8;\">";
            estruturaHtml += "<font face=\"Arial,Helvetica,sans-serif\">" + htmlMsg + "</font>";
            estruturaHtml += "</td>";
            estruturaHtml += "</tr>";

            // Rodapé
            estruturaHtml += "<tr>";
            estruturaHtml += "<td style=\"background-color:#f8fafc;padding:20px 48px;border-top:1px solid #e2e8f0;text-align:center;\">";
            estruturaHtml += "<p style=\"margin:0;font-size:12px;color:#94a3b8;\">Psicologa. Todos os direitos reservados.</p>";
            estruturaHtml += "</td>";
            estruturaHtml += "</tr>";

            estruturaHtml += "</table>";
            estruturaHtml += "</td></tr></table>";
            estruturaHtml += "</body>";
            estruturaHtml += "</html>";

            htmlMsg = estruturaHtml;

            email.Subject = assunto;
            email.Body = htmlMsg;

            SmtpClient smtp = new SmtpClient();
            smtp.DeliveryMethod = SmtpDeliveryMethod.Network;
            smtp.UseDefaultCredentials = false;
            smtp.EnableSsl = true;
            System.Net.NetworkCredential credentials = new System.Net.NetworkCredential(_usuario, _emailPadraoSenha);

            smtp.Credentials = credentials;
            smtp.Host = _smtp;
            smtp.Port = _smtpPorta;

            try
            {
                smtp.Send(email);

                return (true, "");
            }
            catch (Exception ex)
            {
                return (false, ex.Message);
            }
        }

        public static bool EmailValido(string email)
        {
            if (string.IsNullOrWhiteSpace(email))
                return false;

            try
            {
                // Normalize the domain
                email = Regex.Replace(email, @"(@)(.+)$", DomainMapper,
                                      RegexOptions.None, TimeSpan.FromMilliseconds(200));

                // Examines the domain part of the email and normalizes it.
                string DomainMapper(Match match)
                {
                    // Use IdnMapping class to convert Unicode domain names.
                    var idn = new IdnMapping();

                    // Pull out and process domain name (throws ArgumentException on invalid)
                    string domainName = idn.GetAscii(match.Groups[2].Value);

                    return match.Groups[1].Value + domainName;
                }
            }
            catch (RegexMatchTimeoutException e)
            {
                return false;
            }
            catch (ArgumentException e)
            {
                return false;
            }

            try
            {
                return Regex.IsMatch(email,
                    @"^[^@\s]+@[^@\s]+\.[^@\s]+$",
                    RegexOptions.IgnoreCase, TimeSpan.FromMilliseconds(250));
            }
            catch (RegexMatchTimeoutException)
            {
                return false;
            }
        }

        public void GerarIMagemBase64()
        {
        }
    }
}